1	import { Group, Stack } from '@mantine/core';
2	import { Metadata } from 'next';
3	import { notFound, permanentRedirect } from 'next/navigation';
4	import { TableNameSchema } from 'prisma/zod/schemas';
5	import { cache } from 'react';
6	import z from 'zod';
7	
8	import { AutoRefresh } from '@/components/AutoRefresh/AutoRefresh';
9	import { TitleWithYearDropdown } from '@/components/TitleWithYearDropdown/TitleWithYearDropdown';
10	import { YearTable } from '@/components/YearTable/YearTable';
11	import { QualifiedTableName, TableTitle } from '@/lib/tables';
12	import playerRecordService from '@/services/PlayerRecord';
13	import { FootyChannel } from '@/types/FootyChannel';
14	
15	interface PageProps {
16	    params: Promise<{
17	        table: string,
18	    }>,
19	    searchParams?: Promise<{
20	        year?: string;
21	    }>;
22	}
23	
24	/**
25	 * Unpacks and validates page parameters and search parameters for the footy
26	 * table page.
27	 *
28	 * This function validates the table name parameter against the TableNameSchema,
29	 * validates the year search parameter, and ensures the year exists in the
30	 * available years. It also handles canonical URL redirects to ensure consistent
31	 * URL formatting.
32	 *
33	 * @param params - The page route parameters containing the table name
34	 * @param searchParams - The URL search parameters, optionally containing a year
35	 * @returns A promise resolving to an object containing the validated table
36	 * name, year, and all available years
37	 * @throws {notFound} When the table parameter is invalid, year is invalid, or
38	 * year is not in the available years list
39	 * @throws {permanentRedirect} When the current URL doesn't match the canonical
40	 * URL format
41	 *
42	 * @example
43	 * ```tsx
44	 * const { table, year, allYears } = await unpackParams(params, searchParams);
45	 * ```
46	 */
47	const unpackParams = cache(async (
48	    params: PageProps['params'],
49	    searchParams: PageProps['searchParams'],
50	) => {
51	    const { table: tableParam } = await params;
52	
53	    const tableResult = TableNameSchema.safeParse(tableParam);
54	    if (!tableResult.success) notFound();
55	    const table = tableResult.data;
56	
57	    const resolvedSearchParams = await searchParams;
58	    const allYears = await playerRecordService.getAllYears({
59	        completed: false,
60	        mostRecentFirst: true,
61	    });
62	    const yearResult = z.coerce.number().int().min(0).safeParse(resolvedSearchParams?.year ?? 0);
63	    const year = yearResult.success ? yearResult.data : undefined;
64	    if (year === undefined || !allYears.includes(year)) notFound();
65	
66	    const canonicalSearch = year ? `?year=${year}` : '';
67	    const canonicalUrl = `/footy/table/${table}${canonicalSearch}`;
68	    const currentSearch = resolvedSearchParams?.year ? `?year=${resolvedSearchParams.year}` : '';
69	    const currentUrl = `/footy/table/${table}${currentSearch}`;
70	    if (currentUrl !== canonicalUrl) permanentRedirect(canonicalUrl);
71	
72	    return { table, year, allYears };
73	});
74	
75	/**
76	 * Generates metadata for the table page.
77	 * @param props - The page properties containing params and searchParams
78	 * @param props.params - The route parameters
79	 * @param props.searchParams - The search query parameters
80	 * @returns A promise that resolves to the page metadata with the qualified
81	 * table name as title
82	 */
83	export async function generateMetadata(props: PageProps): Promise<Metadata> {
84	    const { table, year } = await unpackParams(props.params, props.searchParams);
85	
86	    return {
87	        title: QualifiedTableName(table, year),
88	    };
89	}
90	
91	/**
92	 * Renders the Footy table page for a specific table and year.
93	 *
94	 * This async server component:
95	 * - Resolves route and query parameters via `unpackParams`.
96	 * - Fetches both qualified and unqualified player records for the selected
97	 *   table/year.
98	 * - Displays a `TitleWithYearDropdown` and a `YearTable` populated with the
99	 *   retrieved data.
100	 *
101	 * @param props - Next.js page props containing dynamic route params and search
102	 * params.
103	 * @returns A React element with year selection controls and table results.
104	 */
105	const TablePage = async (props: PageProps) => {
106	    const { table, year, allYears } = await unpackParams(props.params, props.searchParams);
107	
108	    const [tableQualified, tableUnqualified] = await Promise.all([
109	        playerRecordService.getTable(table, year, true),
110	        playerRecordService.getTable(table, year, false),
111	    ]);
112	
113	    return (
114	        <Stack w="100%" p="xl" align="center">
115	            <AutoRefresh channels={[FootyChannel.Results, FootyChannel.Players]} />
116	            <Group justify="center" w="100%" mb="xl">
117	                <TitleWithYearDropdown order={1} title={`${TableTitle(table)}: `} year={year} validYears={allYears} />
118	            </Group>
119	            <YearTable
120	                table={table}
121	                year={year}
122	                qualified={tableQualified}
123	                unqualified={tableUnqualified}
124	            />
125	        </Stack>
126	    );
127	};
128	
129	export default TablePage;
